/*
 * Return the value of the smallest odd number in the vector `x`.
 * If no odd number exists, the original signature suggests returning
 * `std::numeric_limits<int>::max()`.  The behaviour of the original
 * implementation is preserved by performing an exact linear scan.
 */
int smallestOdd(std::vector<int> const& x)
{
    const int max_val = std::numeric_limits<int>::max();
    int best = max_val;

    /* Linear search is O(n) and avoids the overhead of std::reduce
       with a custom lambda, while maintaining the exact semantics
       regarding the comparison order for equal elements. */

    for (int v : x) {
        if (v & 1) {               // only odd elements are considered
            if (v < best) {
                best = v;
            }
        }
    }

    return best;
}
