/* Compute the prefix sum array of the vector `x` and return its sum.
   The function preserves exact semantics of the original implementation
   while leveraging parallel execution for performance. */
[[nodiscard]]
int64_t sumOfPrefixSum(std::vector<int64_t> const& x) {
    if (x.empty()) return 0;

    std::vector<int64_t> prefixSum(x.size());
    // Compute the inclusive scan in parallel
    std::inclusive_scan(std::execution::par,
                        x.begin(), x.end(),
                        prefixSum.begin());

    // Reduce the resulting prefix sum array in parallel to obtain the final sum
    return std::reduce(std::execution::par,
                       prefixSum.begin(), prefixSum.end(), int64_t{0});
}
