#pragma once
#include <vector>
#include <limits>

/* Return the largest sum of any contiguous subarray in the vector x.
   i.e. if x=[−2, 1, −3, 4, −1, 2, 1, −5, 4] then [4, −1, 2, 1] is the contiguous
   subarray with the largest sum of 6.
   Example:
   input: [−2, 1, −3, 4, −1, 2, 1, −5, 4]
   output: 6
*/

int maximumSubarray(std::vector<int> const& x) {
    // Kadane's algorithm – linear time, constant extra space.
    int currentSum = 0;
    int bestSum = std::numeric_limits<int>::lowest();

    for (int val : x) {
        currentSum += val;
        if (currentSum > bestSum) bestSum = currentSum;
        if (currentSum < 0) currentSum = 0;
    }

    // Handle case where all numbers are negative: bestSum will be still the
    // largest (least negative) element because currentSum never became positive.
    return bestSum;
}
