#include <algorithm>
#include <cstddef>

// Compute the highest node degree in an undirected graph with an adjacency matrix A (row‑major).
// `A` contains only 0/1 values; it's undirected but we treat all entries.
// The function returns the maximum row sum (node degree).
int maxDegree(const std::vector<int> &A, size_t N) {
    // Work with raw pointers for cache‑friendly access and to avoid bounds checks.
    const int *mat = A.data();

    // Parallel reduction to compute maximum degree.
    int global_max = 0;
    #pragma omp parallel
    {
        int local_max = 0;
        #pragma omp for schedule(static)
        for (size_t i = 0; i < N; ++i) {
            const int *row = mat + i * N;
            int degree = 0;
            size_t j = 0;
            // Unroll the inner loop for small unrolling factor.
            for (; j + 7 < N; j += 8) {
                degree += row[j]   + row[j+1] + row[j+2] + row[j+3]
                        + row[j+4] + row[j+5] + row[j+6] + row[j+7];
            }
            for (; j < N; ++j) {
                degree += row[j];
            }
            if (degree > local_max) local_max = degree;
        }
        #pragma omp atomic update
        if (local_max > global_max) global_max = local_max;
    }
    return global_max;
}
