#pragma once
#include <vector>
#include <cstddef>
#include <cstdint>
#include <omp.h>

/* Count the number of edges in a directed graph defined by a row‑major NxN
   adjacency matrix stored in a std::vector<int>.
   The implementation is fully vectorised and optionally multi‑threaded
   (OpenMP enabled).  The function preserves the exact semantics of the
   original version. */
inline int edgeCount(const std::vector<int> &A, size_t N)
{
    // Assume A.size() == N*N; no bounds check for speed.
    const int *data = A.data();
    int total = 0;

    #pragma omp parallel for reduction(+:total) schedule(static)
    for (size_t i = 0; i < N; ++i) {
        size_t base = i * N;
        const int *row = data + base;
        int local = 0;
        // Process the row in chunks of 8 ints for better vectorisation
        size_t j = 0;
        for (; j + 8 <= N; j += 8) {
            local += (row[j]   == 1);
            local += (row[j+1] == 1);
            local += (row[j+2] == 1);
            local += (row[j+3] == 1);
            local += (row[j+4] == 1);
            local += (row[j+5] == 1);
            local += (row[j+6] == 1);
            local += (row[j+7] == 1);
        }
        for (; j < N; ++j) {
            local += (row[j] == 1);
        }
        total += local;
    }

    return total;
}
