#pragma once
#include <array>
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Count the number of values in [0,10), [10, 20), …, [90,100] and
 * put the counts in `bins`.  The function is fully equivalent to the
 * sequential version but uses OpenMP to parallelise the loop while
 * preserving exact behaviour.
 */
inline void binsBy10Count(std::vector<double> const& x, std::array<std::size_t, 10> &bins)
{
    // Initialise the result array to zero
    for (auto &c : bins) c = 0;

    // Each thread will keep a private local array to avoid atomic writes.
    // At the end we reduce the private arrays into the global result.
    #pragma omp parallel
    {
        std::array<std::size_t, 10> local_bins{};
        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < x.size(); ++i) {
            std::size_t bin = static_cast<std::size_t>(x[i] / 10.0);
            /* Clamp to 9 for values exactly 100, which would otherwise produce
               bin = 10 and index out‐of‑bounds.  This keeps the behaviour
               identical to the original sequential implementation which
               also clamps to the last bin. */
            if (bin >= 10) bin = 9;
            ++local_bins[bin];
        }

        // Accumulate private results into the shared array.  Only one thread
        // must perform the merge per bin, so we use critical sections with
        // minimal scope to keep contention low.
        #pragma omp critical
        {
            for (std::size_t b = 0; b < 10; ++b) {
                bins[b] += local_bins[b];
            }
        }
    }
}
