```cpp
#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

#if !defined(M_PI)
# define M_PI 3.14159265358979323846
#endif

/*
 * Compute the discrete Fourier transform (DFT) of a real‑valued input sequence.
 * The algorithm is straightforward O(N²) with an OpenMP parallel outer loop.
 * All numerical behaviour matches the reference implementation; no alterations
 * are made to the output format.
 */
void dft(const std::vector<double>& x, std::vector<std::complex<double>>& output)
{
    const int N = static_cast<int>(x.size());
    output.assign(N, std::complex<double>(0.0, 0.0));

    if (N == 0) return;

    /* Pre‑compute the constant 2π/N to avoid repeated divisions */
    const double twoPiOverN = 2.0 * M_PI / static_cast<double>(N);

    /* Parallelise over the output index k.  The inner loop is embarrassingly
     * parallel and does not share state, so we can safely use a static
     * schedule with chunk size 1. */
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < N; ++k) {
        double realSum = 0.0;
        double imagSum = 0.0;
        const double angleFactor = static_cast<double>(k) * twoPiOverN;
        for (int n = 0; n < N; ++n) {
            const double angle = angleFactor * static_cast<double>(n);
            const double cosp = std::cos(angle);
            const double sinp = std::sin(angle);
            /* Euler's formula: exp(-i*angle) = cos(angle) - i*sin(angle) */
            const double xn = x[n];
            realSum += xn * cosp;
            imagSum -= xn * sinp;   // note the minus sign
        }
        output[k] = std::complex<double>(realSum, imagSum);
    }
}
