    if (points.size() < 1000) {
        for (const auto &p : points) {
            if (p.x >= 0.0)
                bins[p.y >= 0.0 ? 0 : 3] += 1;
            else
                bins[p.y >= 0.0 ? 1 : 2] += 1;
        }
        return;
    }

    // Parallel reduction using thread-local buffers
    const int nthreads = omp_get_max_threads();
    std::vector<std::array<size_t,4>> local(nthreads);
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        local[tid] = {0, 0, 0, 0};

