#pragma once
#include <vector>
#include <algorithm>
#include <cstdint>
#include <cstddef>

/*  A is an NxN adjacency matrix stored in row‑major order.
    Each entry is either 0 or 1.                          */

inline void dfs_iterative(const std::vector<int>& A,
                          size_t start,
                          size_t N,
                          std::vector<uint8_t>& visited,
                          int& count)
{
    std::vector<size_t> stack;
    stack.reserve(N);
    visited[start] = 1;
    count = 1;
    stack.push_back(start);

    while (!stack.empty()) {
        size_t node = stack.back();
        stack.pop_back();

        const size_t base = node * N;
        for (size_t i = 0; i < N; ++i) {
            if (A[base + i] && !visited[i]) {
                visited[i] = 1;
                ++count;
                stack.push_back(i);
            }
        }
    }
}

/* Return the number of vertices in the largest component of the graph
   defined by the adjacency matrix A.                       */
int largestComponent(const std::vector<int>& A, size_t N)
{
    std::vector<uint8_t> visited(N, 0);
    int maxCount = 0;

    for (size_t i = 0; i < N; ++i) {
        if (!visited[i]) {
            int count = 0;
