/* Compute one iteration of a 3‑point 1D Jacobi stencil.
 *
 * For each element:  output[i] = (input[i-1] + input[i] + input[i+1]) / 3
 * Use 0 for out‑of‑bounds indices.  The routine is fully SIMD‑friendly
 * and is parallelised with OpenMP.
 */
inline void jacobi1D(std::vector<double> const& input, std::vector<double> &output) {
    const std::size_t n   = input.size();
    const double     div3 = 1.0 / 3.0;

    // Ensure output has the same size as input
    if (output.size() != n) output.resize(n);

    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        double sum = input[i];          // centre
        if (i > 0)   sum += input[i - 1];
        if (i + 1 < n) sum += input[i + 1];
        output[i] = sum * div3;
    }
}
