49_sparse_la_sparse_lu_decomp:
```cpp
#pragma once
#include <vector>
#include <algorithm>
#include <cstddef>

struct COOElement {
    size_t row, column;
    double value;
};

/*
 * LU factorization of a sparse NxN matrix A (stored in COO format)
 * into L (lower triangular, unit diagonal) and U (upper triangular).
 * L and U are returned as flattened row‑major N×N matrices.
 *
 * The implementation avoids any temporary dense matrices per row and
 * performs the computation directly on contiguous memory.  All loops
 * use a minimal number of bound checks, and frequently accessed
 * values are kept in registers.
 *
 * The algorithm is stable for fill‑in–free matrices that are
 * strictly lower/upper triangular plus a diagonal.
 */
inline void luFactorize(
    const std::vector<COOElement>& A,
    std::vector<double>& L,
    std::vector<double>& U,
    size_t N)
{
    /*--- 1. Build the dense matrix from COO --------------------------------*/
    const size_t NN = N * N;
    std::vector<double> A_dense(NN, 0.0);
    for (const auto& e : A)
        A_dense[e.row * N + e.column] = e.value;

    /*--- 2. LU factorization ----------------------------------------------*/
    L.assign(NN, 0.0);
    U.assign(NN, 0.0);

    for (size_t i = 0; i < N; ++i) {
        // Upper part of row i
        for (size_t j = i; j < N; ++j) {
            double sum = A_dense[i * N + j];
            for (size_t k = 0; k < i; ++k)
                sum -= L[i * N + k] * U[k * N + j];
            U[i * N + j] = sum;
        }

        // Lower part of row i
        for (size_t j = 0; j < i; ++j) {
            double sum = A_dense[i * N + j];
            for (size_t k = 0; k < j; ++k)
                sum -= L[i * N + k] * U[k * N + j];
            L[i * N + j] = sum / U[j * N + j];
        }

        // Unit diagonal of L
        L[i * N + i] = 1.0;
    }
}
