struct COOElement {
    size_t row, column;
    double value;
};

/*
 * Compute the matrix multiplication Y = A * X.
 *   A : sparse MxK matrix (COO)
 *   X : sparse KxN matrix (COO)
 *   Y : dense MxN matrix, row‑major.
 *
 * The implementation builds an index on the rows of X to avoid
 * quadratic scans.  The outer loop is parallelised with OpenMP
 * and atomic primitives guard concurrent updates to Y.
 */
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double>& Y,
          size_t M, size_t K, size_t N)
{
    // Initialise Y
    Y.assign(M * N, 0.0);

    /* Build a mapping from X.row -> list of X elements in that row.
     * Using a vector of vectors instead of an unordered_map gives
     * better cache locality for dense row indices.
     */
    std::vector<std::vector<COOElement>> X_by_row(K);
    for (auto const& x : X) {
        X_by_row[x.row].push_back(x);
    }

    // Parallel over A elements
#pragma omp parallel for schedule(dynamic, 1024)
    for (ptrdiff_t a_idx = 0; a_idx < static_cast<ptrdiff_t>(A.size()); ++a_idx) {
        auto const& a = A[a_idx];
        const size_t rowA = a.row;
        const double valA = a.value;

        if (a.column >= K) continue;            // out of bounds guard
        const auto& rowX = X_by_row[a.column];   // X elements that can multiply with this A

        for (auto const& x : rowX) {
            const size_t colY  = x.column;
            const size_t idx    = rowA * N + colY;
            const double prod   = valA * x.value;
#pragma omp atomic
            Y[idx] += prod;
        }
    }
}
