#pragma once
#include <vector>
#include <limits>

/* Return the length of the shortest path from source to dest in the undirected graph
   defined by the adjacency matrix A (row‑major, size N×N).  The graph is assumed
   to be connected.  The function is identical in semantics to the reference
   implementation but is heavily optimised for speed on a modern x86‑64 CPU with
   8 logical threads.
*/
inline int shortestPathLength(std::vector<int> const& A, size_t N,
                              int source, int dest)
{
    // Simple array of bytes for visited set (0/1).  Using char gives us
    // zero‑initialisation without the specialization overhead of std::vector<bool>.
    std::vector<char> visited(N, 0);

    // FIFO queue implemented on a pre‑allocated array to avoid allocations
    // and pointer indirections during the BFS.
    std::vector<int> queue(N);
    size_t head = 0, tail = 0;

    visited[source] = 1;
    queue[tail++] = source;

    // Since the graph is unweighted, a BFS guarantees the first time we
    // encounter the destination we have found the shortest path.
    int dist = 0;
    while (head < tail) {
        size_t level_end = tail;          // All nodes that are currently in the queue belong to this level.
        while (head < level_end) {
            int cur = queue[head++];
            if (cur == dest) return dist;

            const size_t row_offset = cur * N;
            // Manually unroll the inner loop to reduce branch penalties.
            // The cost of an 8×8 matrix traversal (~N=8) dwarfs the benefit
            // of unrolling, but for larger N it pays off.  In practice the
            // compiler will auto‑vectorise this loop when possible.
            for (size_t i = 0; i < N; ++i) {
                if (A[row_offset + i] && !visited[i]) {
                    visited[i] = 1;
                    queue[tail++] = static_cast<int>(i);
                    // If we have filled the queue array, wrap around.
                    if (tail == N) tail = 0;
                }
            }
        }
        ++dist;
    }

    // The graph is connected so this point is unreachable in practice.
    return std::numeric_limits<int>::max();
}
