#pragma once
#include <vector>
#include <numeric>
#include <omp.h>

/* Compute the reverse prefix sum of the vector x into output.
   Examples:
   input: [1, 7, 4, 6, 6, 2]
   output: [2, 8, 14, 18, 25, 26]
   input: [3, 3, 7, 1, -2]
   output: [-2, -1, 6, 9, 12]
*/
inline void reversePrefixSum(const std::vector<int> &x, std::vector<int> &output)
{
    const std::size_t n = x.size();
    if (n == 0) return;
    output.resize(n);

    /* 1) Compute block sums in parallel:
     *    blockSum[i] = sum of x[i*B .. (i+1)*B-1]
     *    where B = (n + num_threads - 1)/num_threads
     */
    int numThreads = omp_get_max_threads();
    std::size_t blockSize = (n + numThreads - 1) / numThreads;
    std::vector<int> blockSum(numThreads, 0);

#pragma omp parallel
    {
        int t = omp_get_thread_num();
        std::size_t start = t * blockSize;
        std::size_t end   = std::min(start + blockSize, n);
        int s = 0;
        for (std::size_t i = start; i < end; ++i)
            s += x[i];
        blockSum[t] = s;
    }

    /* 2) Prefix scan of block sums (serial – trivial overhead) */
    std::vector<int> blockPrefix(numThreads, 0);
    for (int t = 1; t < numThreads; ++t)
        blockPrefix[t] = blockPrefix[t-1] + blockSum[t-1];

    /* 3) Compute reverse prefix sum for each block in parallel.
     *    We iterate from the end of the block to its start,
     *    adding the blockPrefix value to each element.
     */
#pragma omp parallel
    {
        int t = omp_get_thread_num();
        std::size_t start = t * blockSize;
        std::size_t end   = std::min(start + blockSize, n);
        int acc = 0;
        for (std::size_t i = end; i > start; --i)
        {
            acc += x[i-1];
            output[i-1] = acc + blockPrefix[t];
        }
    }
}
