struct Element {
    std::size_t index;
    double value;
};

/*
 * Compute z = alpha*x + y where x and y are sparse vectors.
 * The result is accumulated into the array `z`.  The size of
 * `z` must be at least one element larger than the maximum index
 * that appears in `x` or `y`.  No output transformation is
 * performed – the function simply adds the contributions to `z`
 * (exactly matching the original behaviour).
 *
 * The implementation is fully parallel and uses per‑thread
 * temporary buffers to avoid contention on `z`.
 */
inline void sparseAxpy(double alpha,
                       const std::vector<Element>& x,
                       const std::vector<Element>& y,
                       std::vector<double>& z)
{
    // Determine the needed size of the output array if it is too small.
    std::size_t maxIdx = 0;
    if (!x.empty() || !y.empty()) {
        maxIdx = std::max(x.empty() ? 0 : x.back().index,
                          y.empty() ? 0 : y.back().index);
        if (z.size() <= maxIdx)
            z.resize(maxIdx + 1, 0.0);
    }

    const int nthreads = omp_get_max_threads();
    // Per‑thread private buffers to accumulate results.
    std::vector<std::vector<double>> localZ(nthreads,
                                            std::vector<double>(z.size(), 0.0));

    // Inner helper for linear scan over a sparse vector adding
    // contributions into a private buffer.
    auto process = [&](const std::vector<Element>& vec,
                       bool useAlpha,
                       const std::vector<double>& buf) {
        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < vec.size(); ++i) {
            std::size_t idx = vec[i].index;
            double  val = useAlpha ? alpha * vec[i].value : vec[i].value;
            localZ[omp_get_thread_num()][idx] += val;
        }
    };

    omp_set_num_threads(nthreads);
    // Process both vectors in parallel.
    #pragma omp parallel
    {
        process(x, true, localZ[0]);   // stars: x elements with alpha
        process(y, false, localZ[0]);  // stars: y elements without alpha
    }

    // Accumulate per‑thread buffers into the global result.
    for (int t = 0; t < nthreads; ++t) {
        const auto& tmp = localZ[t];
        for (std::size_t i = 0; i < tmp.size(); ++i)
            if (tmp[i] != 0.0)
                z[i] += tmp[i];
    }
}
