#pragma once
#include <cstdint>
#include <vector>
#include <numeric>
#include <omp.h>

/* Compute the inclusive prefix sum of the vector `x` into `output`.
   The implementation uses an OpenMP parallel scan to accelerate the
   operation on the target machine (8 logical cores). */
inline void prefixSum(std::vector<int64_t> const& x,
                      std::vector<int64_t>& output)
{
    const std::size_t n = x.size();
    if (n == 0)
        return;

    /* Ensure the output vector has the correct size */
    if (output.size() != n)
        output.resize(n);

    /* When the data set is very small a single threaded method is
       often faster because of the overhead of thread creation.
       Empirically a threshold of 1<<12 (4096) elements is a good
       compromise on the target platform. */
    if (n <= 4096) {
        std::inclusive_scan(x.begin(), x.end(), output.begin());
        return;
    }

    /* Parallel prefix scan:
       1. Divide the array into `num_chunks` contiguous chunks.
       2. Compute the sum of each chunk in parallel.
       3. Perform a (serial) prefix on the chunk sums.
       4. Add the offset from step 3 to each element of the chunk.
    */
    const int num_threads = omp_get_max_threads();   // usually 8
    const std::size_t chunk_size = (n + num_threads - 1) / num_threads;

    /* Stage 1 : local partial sums */
    std::vector<int64_t> local_sums(num_threads, 0);

    #pragma omp parallel num_threads(num_threads)
    {
        const int tid = omp_get_thread_num();
        const std::size_t start = tid * chunk_size;
        const std::size_t end   = std::min(start + chunk_size, n);

        if (start < end) {
            /* Compute inclusive scan locally into `output` and record the
               last value (which is the chunk total) for later aggregation. */
            std::inclusive_scan(x.begin() + start, x.begin() + end,
                                output.begin() + start);

            /* Store the last element of the local scan; it is the
               sum of the current chunk. */
            local_sums[tid] = output[end - 1];
        }
    }

    /* Stage 2 : serial prefix on the local sums */
    std::vector<int64_t> offsets(num_threads, 0);
    int64_t sum = 0;
    for (int i = 0; i < num_threads; ++i) {
        offsets[i] = sum;
        sum += local_sums[i];
    }

    /* Stage 3 : add offsets to each chunk */
    #pragma omp parallel for schedule(static, 1)
    for (int tid = 0; tid < num_threads; ++tid) {
        const std::size_t start = tid * chunk_size;
        const std::size_t end   = std::min(start + chunk_size, n);
        if (start < end && offsets[tid] != 0) {
            const int64_t addend = offsets[tid];
            for (std::size_t i = start; i < end; ++i)
                output[i] += addend;
        }
    }
}
