#include <omp.h>

/* Factorize the matrix A into A=LU where L is a lower triangular matrix and U is an upper
   triangular matrix.  The result is written back into the same array A.
   A is an NxN matrix stored in row‑major order.
*/
inline void luFactorize(std::vector<double>& A, const std::size_t N) {
    const double* restrict A_row;
    double* restrict A_diag = A.data();
    const double* restrict A_col;

    for (std::size_t k = 0; k < N; ++k) {
        const double pivot = A[k * N + k];
        /* Parallelise the update of rows i > k */
        #pragma omp parallel for schedule(static)
        for (std::size_t i = k + 1; i < N; ++i) {
            double* restrict Ai = A.data() + i * N;
            const double* restrict Ak = A.data() + k * N;

            const double factor = Ai[k] / pivot;
            Ai[k] = factor;                     // store L factor

            /* vectorised inner product */
            for (std::size_t j = k + 1; j < N; ++j) {
                Ai[j] -= factor * Ak[j];
            }
        }
    }
}
