constexpr double TWO_PI = 6.283185307179586476925286766559;

inline void fft(std::vector<std::complex<double>> const& x,
                std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output = x;

    // pre‑compute bit‑reversal permutation
    std::size_t m = 0, tmp = N;
    while (tmp >>= 1) ++m;
    std::vector<std::size_t> rev(N, 0);
    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t v = i;
        std::size_t r = 0;
        for (std::size_t j = 0; j < m; ++j)
        {
            r = (r << 1) | (v & 1);
            v >>= 1;
        }
        rev[i] = r;
    }

    // reorder (copy to avoid data race)
    std::vector<std::complex<double>> temp(N);
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
        temp[rev[i]] = output[i];
    output.swap(temp);

    // pre‑compute twiddle factors for each stage
    std::vector<std::complex<double>> twiddles(N / 2);
    for (std::size_t i = 0; i < N / 2; ++i)
    {
        double angle = -TWO_PI * i / N;
        twiddles[i] = std::complex<double>(std::cos(angle), std::sin(angle));
    }

    // iterative radix‑2 Cooley–Tukey
    for (std::size_t len = 2; len <= N; len <<= 1)
    {
        std::size_t half = len >> 1;
        std::size_t step = N / len;
        #pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < N; i += len)
        {
            for (std::size_t j = 0; j < half; ++j)
            {
                std::size_t idx = i + j;
                std::size_t idx2 = idx + half;
                std::complex<double> t = output[idx2] * twiddles[j * step];
                output[idx2] = output[idx] - t;
                output[idx] += t;
            }
        }
    }
}
