/* Point structure */
struct Point {
    double x, y;
};

/* Minimal area of a triangle that can be formed from the given points.
 * The implementation uses a parallel, vectorized O(n³) search that invokes
 * the compiler’s optimization pipeline; the algorithmic complexity is the
 * same as the reference implementation but the code exploits SIMD and
 * multiple threads. */
double smallestArea(const std::vector<Point>& points) {
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    /* Pre‑copy points into two flat arrays to avoid bound checks
     * and allow vectorized accesses. */
    std::vector<double> xs(n), ys(n);
    for (std::size_t i = 0; i < n; ++i) {
        xs[i] = points[i].x;
        ys[i] = points[i].y;
    }

    const double INF = std::numeric_limits<double>::max();
    double minArea = INF;

#pragma omp parallel for collapse(2) schedule(static) reduction(min:minArea)
    for (std::size_t i = 0; i < n - 2; ++i) {
        const double xi = xs[i], yi = ys[i];
        for (std::size_t j = i + 1; j < n - 1; ++j) {
            const double xj = xs[j], yj = ys[j];
            const double dxij = xi - xj;
            const double dyij = yi - yj;
            for (std::size_t k = j + 1; k < n; ++k) {
                /* Cross product (j-i) × (k-i) gives twice the signed area. */
                double area2  = dxij * (ys[k] - yi) - dyij * (xs[k] - xi);
                double area   = std::abs(area2) * 0.5;   // exact area
                if (area < minArea) minArea = area;
            }
        }
    }
    return minArea;
}
