        std::size_t rowBase = i * N;
        std::size_t prevRowBase = (i > 0)     ? (i-1) * N : 0;
        std::size_t nextRowBase = (i + 1 < N) ? (i+1) * N : 0;

        for (std::size_t j = 0; j < N; ++j) {
            int cnt = 0;

            // Vertical neighbors
            if (i > 0     && input[prevRowBase + j] == 1) ++cnt;
            if (i + 1 < N && input[nextRowBase + j] == 1) ++cnt;

            // Horizontal neighbors
            if (j > 0     && input[rowBase + j - 1] == 1) ++cnt;
            if (j + 1 < N && input[rowBase + j + 1] == 1) ++cnt;

            output[rowBase + j] = (cnt == 1) ? 1 : 0;
        }
    }
}
