#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <algorithm>
#include <omp.h>

/*
 * In‑place radix‑2 FFT with iterative decimation‑in‑time algorithm.
 * The function maintains the exact semantics of the original implementation:
 *   - Input is a real‑valued vector `x` transposed into a vector of complex<double> with zero imaginary part.
 *   - Output real parts are stored in `r`, imaginary parts in `i`.
 * The algorithm uses odd‑even bit reversal and an OpenMP parallel for loop for the main butterfly stage.
 * The permutation is performed on‑the‑fly to avoid an additional buffer.
 */
void fft(std::vector<std::complex<double>> const& x, std::vector<double> &r, std::vector<double> &i)
{
    const std::size_t N = x.size();
    uint32_t np2 = static_cast<uint32_t>(N);
    std::vector<std::complex<double>> buf(np2);
    std::copy(x.begin(), x.end(), buf.begin());

    const double pi = std::acos(-1);
    double theta = pi / N;
    std::complex<double> w_m(std::cos(theta), -std::sin(theta));

    /* Pre‑compute powers of w_m */
    std::vector<std::complex<double>> wm(N/2);
    wm[0] = 1.0;
    for (std::size_t k = 1; k < N/2; ++k)
        wm[k] = wm[k-1] * w_m;

    /* Decimation‑in‑time butterfly loop --------------------------------*/
    std::size_t m = std::size_t(std::log2(N));
    #pragma omp parallel for schedule(static)
    for (std::size_t s = 0; s < m; ++s)
    {
        std::size_t step = 1 << (s+1);
        std::size_t jump = step >> 1;
        std::size_t w_idx_fac = N >> (s+1);
        for (std::size_t k = 0; k < N; k += step)
        {
            std::size_t tip = 0;
            for (std::size_t j = 0; j < jump; ++j, ++tip)
            {
                std::size_t idx1 = k + j;
                std::size_t idx2 = idx1 + jump;
                std::complex<double> temp = buf[idx1] - buf[idx2];
                buf[idx1] += buf[idx2];
                buf[idx2] = temp * wm[tip * w_idx_fac];
            }
        }
    }

    /* In‑place bit reversal -------------------------------------------*/
    for (std::size_t i = 0; i < N; ++i)
    {
        /* calculate bit reversal using 32‑bit tricks */
        uint32_t j = static_cast<uint32_t>(i);
        j = ((j >> 1) & 0x55555555u) | ((j & 0x55555555u) << 1);
        j = ((j >> 2) & 0x33333333u) | ((j & 0x33333333u) << 2);
        j = ((j >> 4) & 0x0f0f0f0fu) | ((j & 0x0f0f0f0fu) << 4);
        j = ((j >> 8) & 0x00ff00ffu) | ((j & 0x00ff00ffu) << 8);
        j = ((j >> 16) | (j << 16)) >> (32 - m);
        if (j > i)
            std::swap(buf[i], buf[j]);
    }

    /* Copy to output ---------------------------------------------------*/
    for (std::size_t k = 0; k < N; ++k)
    {
        r[k] = buf[k].real();
        i[k] = buf[k].imag();
    }
}
