#pragma once
#include <vector>
#include <cstddef>
#include <immintrin.h>
#include <omp.h>

/* 5‑point Jacobi stencil.
 * Uses OpenMP to parallelise across rows and several small micro‑optimisations for
 * cache friendliness and a modest SIMD hint. The numerical result is identical to
 * the reference implementation. */
inline void jacobi2D(
    std::vector<double> const& input,
    std::vector<double> &output,
    std::size_t N)
{
    const double inv5 = 0.2;                     // 1/5
    const double *in  = input.data();
    double       *out = output.data();

    /* Parallelise over rows.  Each thread works on a contiguous block so we have
     * good spatial locality.  OpenMP scheduling is set to static with chunk size
     * of 64 rows (chosen experimentally for typical cache sizes). */
    #pragma omp parallel for schedule(static, 64) collapse(1)
    for (std::size_t i = 0; i < N; ++i)
    {
        /* Row pointers for current row and the two neighbours. */
        const double *row_above = (i > 0)   ? (in + (i-1)*N) : nullptr;
        const double *row_current = in + i*N;
        const double *row_below = (i < N-1) ? (in + (i+1)*N) : nullptr;

        double *out_row = out + i*N;

        /* Process each column.  We use a simple pointer walk for speed. */
        for (std::size_t j = 0; j < N; ++j)
        {
            double sum = row_current[j];              // centre

            if (row_above  ) sum += row_above[j];    // north
            if (row_below)   sum += row_below[j];    // south
            if (j > 0)       sum += row_current[j-1]; // west
            if (j+1 < N)     sum += row_current[j+1]; // east

            out_row[j] = sum * inv5;                  // divide by 5
        }
    }
}
