/* Return the k‑th smallest element of the vector x.
 *
 * The function operates on a copy of the input to preserve its
 * original contents, just as the original implementation did.
 * A linear‑time selection algorithm (nth_element) replaces
 * std::sort, giving O(n) average complexity instead of O(n log n).
 */
int findKthSmallest(std::vector<int> const& x, int k) {
    // Copy the input so that it is not modified
    std::vector<int> x_copy = x;

    // nth_element places the element that would be at position k-1
    // (0‑based) into its sorted position; all elements before it
    // are less than or equal to it, all elements after it are
    // greater than or equal to it.
    std::nth_element(x_copy.begin(), x_copy.begin() + (k - 1), x_copy.end());

    // The element at k-1 is now the k‑th smallest
    return x_copy[k - 1];
}
