/* Compute the rank (index in the sorted order) for each element of `x`.
 *
 * The output vector `ranks_` is resized to hold the result and
 * each element `ranks_[i]` is guaranteed to be the position of
 * `x[i]` in the ascending order of `x`.
 *
 * The algorithm is:
 *   1. Generate a vector of indices 0..N-1.
 *   2. Sort those indices using `x` as the key.
 *   3. Assign ranks according to the final sorted order.
 *
 * This implementation uses OpenMP to parallelize the creation of
 * the index vector, which yields a modest speed‑up on multicore
 * systems while keeping the logic identical to the reference
 * implementation.
 */
inline void ranks(std::vector<float> const& x, std::vector<size_t> &ranks_) {
    const std::size_t N = x.size();

    // 1.  Ensure the output vector is the correct size.
    ranks_.resize(N);

    // 2.  Build the index vector in parallel.
    std::vector<size_t> indices(N);
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        indices[i] = i;
    }

    // 3.  Sort the indices based on the values of `x`.
    std::sort(indices.begin(), indices.end(),
              [&x](size_t i1, size_t i2) { return x[i1] < x[i2]; });

    // 4.  Translate the sorted indices into ranks.
    for (std::size_t rank = 0; rank < N; ++rank) {
        ranks_[indices[rank]] = rank;
    }
}
