#pragma once
#include <vector>
#include <algorithm>
#include <cmath>
#include <cstddef>
#include <omp.h>

struct Point
{
    double x, y;
};

inline double dist2(Point const& a, Point const& b)
{
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return dx * dx + dy * dy;
}

inline double dist(Point const& a, Point const& b)
{
    return std::sqrt(dist2(a, b));
}

inline double cross(Point const& a, Point const& b, Point const& c)
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

/* Return the perimeter of the smallest convex polygon that contains
   all the points in the vector points.  */
double convexHullPerimeter(std::vector<Point> const& points)
{
    std::size_t n = points.size();
    if (n < 3) return 0.0;

    std::vector<Point> pts(points);
    std::sort(pts.begin(), pts.end(), [](Point const& a, Point const& b) {
        return a.x < b.x || (a.x == b.x && a.y < b.y);
    });

    std::vector<Point> hull(2 * n);
    std::size_t k = 0;

    /* lower hull */
    for (std::size_t i = 0; i < n; ++i) {
        while (k >= 2 && cross(hull[k - 2], hull[k - 1], pts[i]) <= 0.0) --k;
        hull[k++] = pts[i];
    }

    /* upper hull */
    for (std::size_t i = n - 1, t = k + 1; i > 0; --i) {
        while (k >= t && cross(hull[k - 2], hull[k - 1], pts[i - 1]) <= 0.0) --k;
        hull[k++] = pts[i - 1];
    }

    hull.resize(k - 1);

    double perimeter = 0.0;
#pragma omp parallel for reduction(+:perimeter)
    for (std::size_t i = 0; i < hull.size(); ++i) {
        std::size_t j = (i + 1) % hull.size();
        perimeter += dist(hull[i], hull[j]);
    }

    return perimeter;
}
