/* Multiply the matrix A by the matrix B. Store the results in the matrix C.
   A is an MxK matrix, B is a KxN matrix, and C is a MxN matrix. The matrices are stored in row-major.
   Example:
   input: A=[[1, -1, 2], [0, -2, 1]] B=[[4, 1], [-1, 0], [2, 2]]
   output: C=[[9, 5], [4, 2]]
   The function preserves any pre‑existing values in C, just accumulating the product onto them.
*/
inline void gemm(const std::vector<double> &A,
                 const std::vector<double> &B,
                 std::vector<double> &C,
                 size_t M, size_t K, size_t N)
{
    // Block sizes chosen experimentally for typical cache sizes
    constexpr size_t BLOCK_M = 64; // rows of A / C
    constexpr size_t BLOCK_K = 64; // columns of A / rows of B
    constexpr size_t BLOCK_N = 64; // columns of B / C

#pragma omp parallel for schedule(static)
    for (size_t bi = 0; bi < M; bi += BLOCK_M) {
        size_t i_max = std::min(bi + BLOCK_M, M);
        for (size_t bk = 0; bk < K; bk += BLOCK_K) {
            size_t k_max = std::min(bk + BLOCK_K, K);
            for (size_t bj = 0; bj < N; bj += BLOCK_N) {
                size_t j_max = std::min(bj + BLOCK_N, N);
                // Small local buffer for a sub‑matrix of B to maximize cache reuse
                for (size_t i = bi; i < i_max; ++i) {
                    size_t a_offset = i * K;
                    size_t c_offset = i * N;
                    for (size_t k = bk; k < k_max; ++k) {
                        double aik = A[a_offset + k];
                        size_t b_offset = k * N;
                        for (size_t j = bj; j < j_max; ++j) {
                            C[c_offset + j] += aik * B[b_offset + j];
                        }
                    }
                }
            }
        }
    }
}
