struct Point {
    double x, y;
};

inline double cross(const Point& a, const Point& b, const Point& c) noexcept {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

/* Find the convex hull of `points` using the monotone chain algorithm
 * and store the result in `hull`.  The order of points in `hull`
 * starts at the point with the smallest x (and y) and proceeds
 * counter‑clockwise.
 */
inline void convexHull(const std::vector<Point>& points, std::vector<Point>& hull) noexcept {
    std::size_t n = points.size();
    if (n < 3) {                          // degenerate case
        hull = points;
        return;
    }

    // Make a local copy and sort it
    std::vector<Point> sorted(points);    // copy
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) noexcept {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    // Allocate twice as many as the maximum possible number of hull points
    std::vector<Point> temp;
    temp.reserve(2 * n);

    // Build lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (temp.size() >= 2 &&
               cross(temp[temp.size() - 2], temp[temp.size() - 1], sorted[i]) <= 0.0) {
            temp.pop_back();
        }
        temp.push_back(sorted[i]);
    }

    // Build upper hull; skip the first and last point of the lower hull
    for (std::size_t i = n - 1; i > 0; --i) {
        while (temp.size() >= n + 1 &&
               cross(temp[temp.size() - 2], temp[temp.size() - 1], sorted[i - 1]) <= 0.0) {
            temp.pop_back();
        }
        temp.push_back(sorted[i - 1]);
    }

    // Remove the duplicated first/last point
    temp.pop_back();                      // last = first

    hull = std::move(temp);               // move result
}
