// Edge kernel
static constexpr int16_t edgeKernel[3][3] = {
    {-1, -1, -1},
    {-1,  8, -1},
    {-1, -1, -1}
};

/* Convolve the edge kernel with a grayscale image.
   Each pixel is replaced with the dot product of itself and its neighbors
   with the edge kernel.  Out‑of‑bounds indices contribute 0.  Results
   are clamped to [0,255].  imageIn and imageOut are N×N row‑major
   grayscale images.
*/
inline void convolveKernel(const std::vector<int>& imageIn,
                           std::vector<int>& imageOut,
                           size_t N) noexcept
{
    // Ensure output has right size
    imageOut.resize(N * N);

    // Parallelize over rows
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        const int* const rowPtr = imageIn.data() + i * N;
        int* const outRow = imageOut.data() + i * N;

        for (size_t j = 0; j < N; ++j)
        {
            int sum = 0;

            // Manually unroll the 3×3 convolution
            // Top row
            sum += (i > 0) ? rowPtr[-N + (j > 0 ? j-1 : 0)] * edgeKernel[0][0] : 0;
            sum += (i > 0) ? rowPtr[-N + j] * edgeKernel[0][1]                          : 0;
            sum += (i > 0) ? rowPtr[-N + (j+1 < N ? j+1 : N-1)] * edgeKernel[0][2]      : 0;
            // Middle row
            sum += (j > 0)   ? rowPtr[j-1] * edgeKernel[1][0] : 0;
            sum += rowPtr[j] * edgeKernel[1][1];
            sum += (j+1 < N ? rowPtr[j+1] : 0) * edgeKernel[1][2];
            // Bottom row
            sum += (i+1 < N) ? rowPtr[N + (j > 0 ? j-1 : 0)] * edgeKernel[2][0] : 0;
            sum += (i+1 < N) ? rowPtr[N + j] * edgeKernel[2][1]                           : 0;
            sum += (i+1 < N) ? rowPtr[N + (j+1 < N ? j+1 : N-1)] * edgeKernel[2][2]     : 0;

            // Clamp to [0,255]
            outRow[j] = (sum <= 0) ? 0 : (sum >= 255 ? 255 : sum);
        }
    }
}
