// Sort all non‑zero elements of `x` while keeping 0‑positions unchanged.
inline void sortIgnoreZero(std::vector<int> &x)
{
    // Pre‑allocate reserve to avoid reallocations.
    std::vector<int> nonZero;
    nonZero.reserve(x.size());

    // First pass: collect non‑zero values.
    for (int v : x) {
        if (v != 0) {
            nonZero.push_back(v);
        }
    }

    // Sort the collected values.
    std::sort(nonZero.begin(), nonZero.end());

    // Second pass: replace non‑zero positions with sorted values.
    auto nzIt = nonZero.begin();
    for (int &v : x) {
        if (v != 0) {
            v = *nzIt++;
        }
    }
}
