#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   Example:

   input: A=[{0,0,1}, {0,1,1}, {1,1,-2}] b=[1,4]
   output: x=[3,-2]
*/
inline void solveLinearSystem(std::vector<COOElement> const& A,
                              std::vector<double> const& b,
                              std::vector<double>& x,
                              size_t N)
{
    /* Build a dense matrix from the COO input.
       The matrix size is N×N; unsurprisingly this is the
       dominating memory requirement for the algorithm.
       The construction itself is embarrassingly parallel. */
    std::vector<std::vector<double>> M(N, std::vector<double>(N, 0.0));
    #pragma omp parallel for schedule(static)
    for (size_t idx = 0; idx < A.size(); ++idx) {
        const auto& e = A[idx];
        M[e.row][e.column] = e.value;
    }

    /* Make a private copy of the RHS vector for the Gaussian elimination */
    std::vector<double> rhs = b;
    x.assign(N, 0.0);                // result placeholder

    /* Gaussian elimination with partial pivoting.
       The outer loop must be serial because each step
       depends on the previous one, but the inner work
       can be parallelised. */
    for (size_t i = 0; i < N; ++i) {
        /* Find pivot row on column i, using a parallel reduction */
        size_t pivot = i;
        double maxVal = std::abs(M[i][i]);

        #pragma omp parallel
        {
            double localMax = std::abs(M[i][i]);
            size_t localIdx = i;

            #pragma omp for nowait
            for (size_t k = i + 1; k < N; ++k) {
                double absVal = std::abs(M[k][i]);
                if (absVal > localMax) {
                    localMax = absVal;
                    localIdx = k;
                }
            }

            #pragma omp critical
            {
                if (localMax > maxVal) {
                    maxVal = localMax;
                    pivot = localIdx;
                }
            }
        }

        /* Swap current row with the pivot row */
        if (pivot != i) {
            std::swap_ranges(M[i].begin(), M[i].end(), M[pivot].begin());
            std::swap(rhs[i], rhs[pivot]);
        }

        /* Eliminate entries below the pivot */
        const double pivotVal = M[i][i];
        #pragma omp parallel for schedule(static)
        for (size_t k = i + 1; k < N; ++k) {
            const double factor = -M[k][i] / pivotVal;
            /* Zero out the lower triangular element first */
            M[k][i] = 0.0;
            /* Update the rest of the row in parallel */
            for (size_t j = i + 1; j < N; ++j) {
                M[k][j] += factor * M[i][j];
            }
            rhs[k] += factor * rhs[i];
        }
    }

    /* Back substitution – this is inherently sequential
       but the dimension is usually moderate for a
       Gaussian elimination solver. */
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = rhs[i];
        for (int j = static_cast<int>(i) + 1; j < static_cast<int>(N); ++j)
            sum -= M[i][j] * x[j];
        x[i] = sum / M[i][i];
    }
}
