#pragma once
#include <vector>

/* Return true if `val` is only in one of vectors x or y.
   Return false if it is in both or neither. */
inline bool xorContains(std::vector<int> const& x,
                        std::vector<int> const& y,
                        int val) noexcept
{
    bool foundInX = false;
    bool foundInY = false;

    /* Fast linear search – O(n) but very cheap for typical sized
       vectors.  The loop is annotated with OpenMP pragmas so that a
       large vector can be processed in parallel on an 8‑core system. */
#   pragma omp parallel sections
    {
        /* Search in the first vector. */
        #   pragma omp section
        {
            /* Using a plain for loop gives the compiler the
               highest chance of vectorisation. */
            for (std::size_t i = 0, n = x.size(); i < n; ++i)
                if (x[i] == val)
                {
                    foundInX = true;
                    break;          // early exit is safe inside a section
                }
        }

        /* Search in the second vector. */
        #   pragma omp section
        {
            for (std::size_t i = 0, n = y.size(); i < n; ++i)
                if (y[i] == val)
                {
                    foundInY = true;
                    break;
                }
        }
    }

    /* XOR of the two results gives the required Boolean value. */
    return foundInX ^ foundInY;
}
