    /* pointer access for faster loop */
    const double *restrict a = A.data();
    const double *restrict vx = x.data();
          double *restrict vy = y.data();

    /* basic blocking for cache locality */
    const size_t block = 64;          /* block size (tune for your system) */

#pragma omp parallel
    {
        /* allocate a small stack buffer for the accumulator to avoid
           memory traffic when unrolling, but keep across iterations */
#pragma omp for schedule(static)
        for (size_t i = 0; i < M; i += block) {
            size_t i_end = (i + block > M) ? M : i + block;
            for (size_t ii = i; ii < i_end; ++ii) {
                double sum = 0.0;
                /* inner loop unrolled by 4 for a bit of speed */
                size_t jj = 0;
                size_t j_end = N & ~3UL;   /* largest multiple of 4 <= N */
                for (; jj < j_end; jj += 4) {
                    double a0 = a[ii * N + jj];
                    double a1 = a[ii * N + jj + 1];
                    double a2 = a[ii * N + jj + 2];
                    double a3 = a[ii * N + jj + 3];
                    sum += a0 * vx[jj]      +
                           a1 * vx[jj + 1]  +
                           a2 * vx[jj + 2]  +
                           a3 * vx[jj + 3];
                }
                for (; jj < N; ++jj) {
                    sum += a[ii * N + jj] * vx[jj];
                }
                vy[ii] = sum;
            }
        }
    }
