#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row-major. x and b have N elements.
   Example:
   input: A=[[1,4,2], [1,2,3], [2,1,3]] b=[11, 11, 13]
   output: x=[3, 1, 2]
*/
void solveLinearSystem(const std::vector<double>& A,
                       const std::vector<double>& b,
                       std::vector<double>& x,
                       std::size_t N)
{
    // Quick corner‑case handling
    if (N == 0) { return; }

    // Work on copies – we must not modify the caller data
    std::vector<double> a(A);   // matrix copy
    std::vector<double> bv(b);  // RHS copy

    const double *a_mat = a.data();
    double *rhs = bv.data();

    // Gaussian elimination – forward elimination
    for (std::size_t i = 0; i < N - 1; ++i) {
        std::size_t idx = i * N + i;
        double pivot = a_mat[idx];

        /* Preserve original behaviour – abort if pivot is zero */
        if (pivot == 0.0) { return; }

        /* Compute elimination factors and update the rows below.
           The inner operations are embarrassingly parallel and have no
           cross‑row data races, so we can parallelise the subtraction
           loop.  We also use a cache‑friendly inner loop with pointer.
        */
        #pragma omp parallel for schedule(static)
        for (std::size_t j = i + 1; j < N; ++j) {
            double factor = a_mat[j * N + i] / pivot;
            double* row_j = a_mat + j * N;
            const double* row_i = a_mat + i * N;
            for (std::size_t k = i; k < N; ++k) {
                row_j[k] -= factor * row_i[k];
            }
            rhs[j] -= factor * rhs[i];
        }
    }

    // Back substitution – sequential (no data dependencies)
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        const double* row = a_mat + i * N;
        for (std::size_t j = i + 1; j < N; ++j) {
            sum += row[j] * x[j];
        }
        x[i] = (rhs[i] - sum) / row[i];
    }
}
