// ---------------------------------------------------------------------------
// Optimised FFT that preserves the behaviour of the original function.
// ---------------------------------------------------------------------------

constexpr double PI = 3.14159265358979323846264338327950288;

// Pre‑compute bit‑reverse indices for a given FFT size.
inline std::vector<unsigned int>
build_bitrev_table(unsigned int N)
{
    unsigned int m = static_cast<unsigned int>(std::log2(N));
    std::vector<unsigned int> rev(N);

    for (unsigned int i = 0; i < N; ++i) {
        unsigned int x = i;
        unsigned int r = 0;
        for (unsigned int j = 0; j < m; ++j) {
            r = (r << 1) | (x & 1u);
            x >>= 1;
        }
        rev[i] = r;
    }
    return rev;
}

// Helper to pre‑compute twiddle factors for all stages.
inline std::vector<std::vector<std::complex<double>>>
build_twiddle_tables(unsigned int N)
{
    unsigned int stages = static_cast<unsigned int>(std::log2(N));
    std::vector<std::vector<std::complex<double>>> tables(stages);

    for (unsigned int s = 0; s < stages; ++s) {
        unsigned int m = 1u << (s + 1);
        unsigned int half = m >> 1;
        tables[s].resize(half);
        double angle = -2.0 * PI / m;          // note the minus sign (conjugate)
        for (unsigned int k = 0; k < half; ++k)
            tables[s][k] = std::polar(1.0, angle * k);
    }
    return tables;
}

inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    const unsigned int N = static_cast<unsigned int>(x.size());
    if (N <= 1) return;                       // nothing to do

    // ------------------------------------------------
    // 1) Cooley–Tukey radix‑2 DIT (iterative) with Björn‑style bit reversal
    // ------------------------------------------------
    const auto bitrev = build_bitrev_table(N);
    auto twiddles = build_twiddle_tables(N);

    // Bit‑reverse permutation (in‑place)
    for (unsigned int i = 0; i < N; ++i) {
        unsigned int j = bitrev[i];
        if (j > i)
            std::swap(x[i], x[j]);
    }

    // Butterfly stages
#pragma omp parallel for schedule(static)
    for (unsigned int s = 0; s < (unsigned int)std::log2(N); ++s) {
        unsigned int m = 1u << (s + 1);
        unsigned int half = m >> 1;
        const std::vector<std::complex<double>>& W = twiddles[s];

        for (unsigned int k = 0; k < half; ++k) {
            std::complex<double> w = W[k];
            for (unsigned int j = k; j < N; j += m) {
                unsigned int l = j + half;
                std::complex<double> t = x[l] * w;
                x[l] = x[j] - t;
                x[j] += t;
            }
        }
    }

    // ------------------------------------------------
    // 2) Conjugate the result
    // ------------------------------------------------
#pragma omp parallel for schedule(static)
    for (unsigned int i = 0; i < N; ++i) {
        x[i] = std::conj(x[i]);
    }
}
