   Example:

   input: [{title="Green Eggs and Ham", pages=72}, {title="gulliver's travels", pages=362}, {title="Stories of Your Life", pages=54}, {title="Hamilton", pages=818}]
   output: 2
*/
size_t findLastShortBook(std::vector<Book> const& books) {
    if (books.empty()) return 0;

    // Find the maximum index satisfying the condition by scanning in parallel.
    // Use a signed integer for the index to allow an initial value of -1.
    long long last_index = -1;

    #pragma omp parallel for schedule(static)
    for (long long i = 0; i < static_cast<long long>(books.size()); ++i) {
        if (books[i].pages < 100) {
            #pragma omp atomic update
            if (i > last_index) last_index = i;
        }
    }

    // If no book met the condition, return books.size() (the sentinel value).
    return static_cast<size_t>(last_index == -1 ? books.size() : last_index);
}
