/* Find the root of the set containing 'x' using the DSU parent array.
   This function performs no path compression to avoid data races.
*/
static inline int dsu_find(const std::vector<std::atomic<int>>& parent, int x) {
    while (true) {
        int p = parent[x].load(std::memory_order_acquire);
        if (p == x) return x;
        x = p;
    }
}

/* Attempt to union the sets containing 'a' and 'b'.
   The operation uses atomic compare_exchange to avoid conflicts.
*/
static inline void dsu_union(const std::vector<std::atomic<int>>& parent, int a, int b) {
    int root_a = dsu_find(parent, a);
    int root_b = dsu_find(parent, b);
    if (root_a == root_b) return;
    // Arbitrarily make root_b the new parent; use CAS to ensure only one thread
    if (!parent[root_a].compare_exchange_strong(root_a, root_b,
                                                std::memory_order_acq_rel,
                                                std::memory_order_acquire)) {
        // If CAS failed, another thread changed the parent; nothing to do
    }
}

/* Count the number of connected components in the undirected graph defined by the adjacency matrix A.
   A is an NxN adjacency matrix stored in row-major order.
*/
int componentCount(const std::vector<int>& A, size_t N) {
    // DSU parent array, one element per node
    std::vector<std::atomic<int>> parent(N);
    for (int i = 0; i < static_cast<int>(N); ++i) parent[i].store(i, std::memory_order_relaxed);

    // Parallel union for all edges (i < j)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        const int offset = i * static_cast<int>(N);
        for (int j = i + 1; j < static_cast<int>(N); ++j) {
            if (A[offset + j] == 1) {
                dsu_union(parent, i, j);
            }
        }
    }

    // Count unique roots
    std::vector<char> seen(N, 0);
    int components = 0;
    for (int i = 0; i < static_cast<int>(N); ++i) {
        int root = dsu_find(parent, i);
        if (!seen[root]) {
            seen[root] = 1;
            ++components;
        }
    }
    return components;
}
