size_t findFirstEven(const std::vector<int>& x) {
    const size_t n = x.size();
    if (n == 0) return 0;

    // Use a raw pointer for faster access and allow the compiler
    // to vectorise the loop if possible.
    const int* p = x.data();

    // Local copy of the size to avoid repeated bound checks.
    size_t i = 0;
#if defined(__AVX2__)
    // SIMD fallback for AVX2 capable targets.
    const size_t simdStep = 8; // 8 * 32‑bit ints = 256 bits
    size_t lim = n - (n % simdStep);
    for (; i < lim; i += simdStep) {
        __m256i chunk   = _mm256_loadu_si256(reinterpret_cast<const __m256i*>(p + i));
        __m256i mask    = _mm256_and_si256(chunk, _mm256_set1_epi32(1));
        __m256i zeroes  = _mm256_setzero_si256();
        __m256i cmp     = _mm256_cmpeq_epi32(mask, zeroes);
        int maskVal = _mm256_movemask_epi8(cmp);
        // Each byte is 4 bits, so we need to shift by 2 to get 8 lanes.
        maskVal >>= 2;
        if (maskVal) {
            // Find the first set bit.
            int offset = __builtin_ctz(maskVal);
            return i + offset;
        }
    }
#endif
    // Scalar fallback for the remaining (or non‑AVX2) part.
    for (; i < n; ++i) {
        if ((p[i] & 1) == 0) {
            return i;
        }
    }
    return n;
}
