#pragma once
#include <vector>
#include <algorithm>
#include <limits>
#include <cmath>
#include <cstddef>
#include <cmath>
#include <omp.h>

struct Point {
    double x, y;
};

inline double dist2(const Point &a, const Point &b) noexcept
{
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return dx * dx + dy * dy;
}

// Merge two halves sorted by y-coordinate during the recursive step.
static void mergeY(std::vector<Point> &tmp, std::vector<Point> &arr,
                   size_t l, size_t m, size_t r)
{
    size_t i = l, j = m, k = l;
    while (i < m && j < r) {
        if (arr[i].y < arr[j].y) {
            tmp[k++] = arr[i++];
        } else {
            tmp[k++] = arr[j++];
        }
    }
    while (i < m) tmp[k++] = arr[i++];
    while (j < r) tmp[k++] = arr[j++];
    for (size_t t = l; t < r; ++t) arr[t] = tmp[t];
}

// Recursive helper that returns the minimal squared distance in arr[l..r)
// The input array is sorted by x; on exit it is sorted by y.
static double closestRec(std::vector<Point> &arr, std::vector<Point> &tmp,
                         size_t l, size_t r) noexcept
{
    size_t n = r - l;
    if (n <= 3) {
        double best = std::numeric_limits<double>::max();
        for (size_t i = l; i < r; ++i)
            for (size_t j = i + 1; j < r; ++j)
                best = std::min(best, dist2(arr[i], arr[j]));
        // sort by y
        std::sort(arr.begin() + l, arr.begin() + r,
                  [](const Point &a, const Point &b) { return a.y < b.y; });
        return best;
    }

    size_t m = (l + r) >> 1;
    double midx = arr[m].x;

    double dl = closestRec(arr, tmp, l, m);
    double dr = closestRec(arr, tmp, m, r);
    double d = std::min(dl, dr);

    // Merge by y-coordinate for the strip construction
    mergeY(tmp, arr, l, m, r);

    // Build strip of points whose x is within sqrt(d) of midx
    std::vector<Point> strip;
    strip.reserve(n);
    double d_sqrt = std::sqrt(d);
    for (size_t i = l; i < r; ++i) {
        if (std::fabs(arr[i].x - midx) < d_sqrt)
            strip.push_back(arr[i]);
    }

    // Compare each point in strip with next up to 7 points
    size_t sz = strip.size();
    for (size_t i = 0; i < sz; ++i) {
        for (size_t j = i + 1; j < sz && (strip[j].y - strip[i].y) < d_sqrt; ++j) {
            double dd = dist2(strip[i], strip[j]);
            if (dd < d) d = dd;
        }
    }
    return d;
}

double closestPair(std::vector<Point> const& points) {
    size_t n = points.size();
    if (n < 2) return 0.0;

    // Copy and sort by x-coordinate
    std::vector<Point> arr(points.begin(), points.end());
    std::sort(arr.begin(), arr.end(),
              [](const Point &a, const Point &b) { return a.x < b.x; });

    // Temporary array for merging
    std::vector<Point> tmp(n);

    // Main recursive algorithm
    double best_sq = closestRec(arr, tmp, 0, n);

    return std::sqrt(best_sq);
}
