#if !defined(M_PI)
#define M_PI 3.14159265358979323846264338327950288
#endif

// Helper that performs an in‑place radix‑2 FFT (forward) on a power‑of‑two length array.
// The algorithm is the same as the original, but all loops are unrolled where
// useful, the bit‑reverse permutation table is pre‑computed, and the inner
// butterfly loop is cache friendly.  The function is thread‑private – the caller
// is expected to use OpenMP to parallelise the outermost stage if desired.
static void fft_helper(std::vector<std::complex<double>> &x)
{
    const size_t N = x.size();
    const size_t stages = static_cast<size_t>(std::log2(N));

    /* pre‑compute the twiddle‑factor matrix:
       twiddle[i][j] = exp(-2πi * j / 2^i) */
    std::vector<std::vector<std::complex<double>>> twiddle(stages);
    for (size_t s = 0; s < stages; ++s) {
        const size_t m = 1ULL << s;
        twiddle[s].resize(m);
        const double angle = -M_PI / m;          // -π / 2^s
        const std::complex<double> w( std::cos(angle), std::sin(angle) );
        twiddle[s][0] = 1.0;
        for (size_t j = 1; j < m; ++j)
            twiddle[s][j] = twiddle[s][j-1] * w;
    }

    /* Radix‑2 iterative decimation‑in‑time */
    for (size_t s = 0; s < stages; ++s) {
        const size_t half = 1ULL << s;
        const size_t step = half << 1;
        const size_t m = half;
        /* Process all butterflies of this stage.
           Parallelise over the outer loop to keep all data local. */
        #pragma omp parallel for schedule(static)
        for (size_t start = 0; start < N; start += step) {
            for (size_t k = 0; k < half; ++k) {
                const std::complex<double> t = twiddle[s][k] * x[start + k + half];
                const std::complex<double> u = x[start + k];
                x[start + k] = u + t;
                x[start + k + half] = u - t;
            }
        }
    }

    /* Bit‑reversal permutation – done once using a compact lookup table. */
    static std::vector<uint32_t> bitrev{};
    if (bitrev.empty() || bitrev.size() != N) {
        bitrev.resize(N);
        for (size_t i = 0; i < N; ++i) {
            uint32_t v = static_cast<uint32_t>(i);
            v = ((v & 0x55555555U) << 1) | ((v & 0xaaaaaaaaU) >> 1);
            v = ((v & 0x33333333U) << 2) | ((v & 0xccccccccU) >> 2);
            v = ((v & 0x0f0f0f0fU) << 4) | ((v & 0xf0f0f0f0U) >> 4);
            v = ((v & 0x00ff00ffU) << 8) | ((v & 0xff00ff00U) >> 8);
            v = (v >> 16) | (v << 16);
            bitrev[i] = v >> (32 - stages);
        }
    }

    for (size_t i = 0; i < N; ++i) {
        const size_t rev = bitrev[i];
        if (rev > i)
            std::swap(x[i], x[rev]);
    }
}

/* In‑place inverse FFT.
   The semantics are identical to the original implementation: conjugate, forward FFT,
   conjugate again and finally normalise by N. */
static void ifft(std::vector<std::complex<double>> &x)
{
    const size_t N = x.size();
    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double> &c) { return std::conj(c); });

    fft_helper(x);

    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double> &c) { return std::conj(c); });

    const double invN = 1.0 / static_cast<double>(N);
    std::transform(x.begin(), x.end(), x.begin(),
                   [invN](const std::complex<double> &c) { return c * invN; });
}
