#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

// Parallel, cache‑friendly implementation of one Game of Life step
// The algorithm is identical to the original specification.
inline void gameOfLife(std::vector<int> const& input,
                       std::vector<int> &output,
                       size_t N)
{
    // Basic bounds checks (optional, can be omitted in a performance test)
    if (N == 0) return;

    const int *in  = input.data();
    int       *out = output.data();

    // Parallelize over rows and process the inner region first (no border checks)
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        size_t base = i * N;
        if (i == 0 || i == N - 1) {          // top or bottom border
            for (size_t j = 0; j < N; ++j) {
                int sum = 0;
                if (i > 0)
                    sum += in[(i - 1) * N + j];
                if (i < N - 1)
                    sum += in[(i + 1) * N + j];
                if (j > 0)
                    sum += in[base + j - 1];
                if (j < N - 1)
                    sum += in[base + j + 1];
                if (i > 0 && j > 0)
                    sum += in[(i - 1) * N + j - 1];
                if (i > 0 && j < N - 1)
                    sum += in[(i - 1) * N + j + 1];
                if (i < N - 1 && j > 0)
                    sum += in[(i + 1) * N + j - 1];
                if (i < N - 1 && j < N - 1)
                    sum += in[(i + 1) * N + j + 1];

                int cur = in[base + j];
                if (cur == 1) {
                    out[base + j] = (sum == 2 || sum == 3) ? 1 : 0;
                } else {
                    out[base + j] = (sum == 3) ? 1 : 0;
                }
            }
        } else {                            // interior rows (no boundary checks)
            size_t j = 0;
            for (; j + 3 < N; j += 4) {
                // unroll 4 columns
                int sum0 =  in[(i-1)*N + j]   + in[(i+1)*N + j]   + in[base + j-1]   + in[base + j+1]   + in[(i-1)*N + j-1] + in[(i-1)*N + j+1] + in[(i+1)*N + j-1] + in[(i+1)*N + j+1];
                int sum1 =  in[(i-1)*N + j+1] + in[(i+1)*N + j+1] + in[base + j]     + in[base + j+2]   + in[(i-1)*N + j]   + in[(i-1)*N + j+2]   + in[(i+1)*N + j]   + in[(i+1)*N + j+2];
                int sum2 =  in[(i-1)*N + j+2] + in[(i+1)*N + j+2] + in[base + j+1]   + in[base + j+3]   + in[(i-1)*N + j+1] + in[(i-1)*N + j+3] + in[(i+1)*N + j+1] + in[(i+1)*N + j+3];
                int sum3 =  in[(i-1)*N + j+3] + in[(i+1)*N + j+3] + in[base + j+2]   + in[base + j+4]   + in[(i-1)*N + j+2] + in[(i-1)*N + j+4] + in[(i+1)*N + j+2] + in[(i+1)*N + j+4];

                int cur0 = in[base + j];
                int cur1 = in[base + j + 1];
                int cur2 = in[base + j + 2];
                int cur3 = in[base + j + 3];

                out[base + j]     = (cur0 == 1) ? ((sum0==2||sum0==3)?1:0) : ((sum0==3)?1:0);
                out[base + j + 1] = (cur1 == 1) ? ((sum1==2||sum1==3)?1:0) : ((sum1==3)?1:0);
                out[base + j + 2] = (cur2 == 1) ? ((sum2==2||sum2==3)?1:0) : ((sum2==3)?1:0);
                out[base + j + 3] = (cur3 == 1) ? ((sum3==2||sum3==3)?1:0) : ((sum3==3)?1:0);
            }
            // Tail of row (remaining columns)
            for (; j < N; ++j) {
                int sum =  in[(i-1)*N + j]   + in[(i+1)*N + j]   + in[base + j-1]   + in[base + j+1]   + in[(i-1)*N + j-1] + in[(i-1)*N + j+1] + in[(i+1)*N + j-1] + in[(i+1)*N + j+1];
                int cur = in[base + j];
                out[base + j] = (cur == 1) ? ((sum==2||sum==3)?1:0) : ((sum==3)?1:0);
            }
        }
    }
}
